import { Pool } from 'pg'

const pool = new Pool({
  connectionString: process.env.DATABASE_URL || 'postgresql://architect:architect_dev_2026@localhost:5432/shrooly',
})

const migrations = [
  `ALTER TABLE grows ADD COLUMN IF NOT EXISTS species_profile_id INT REFERENCES species_profiles(id)`,
  `CREATE INDEX IF NOT EXISTS idx_grows_species_profile_id ON grows(species_profile_id)`,
]

async function migrate() {
  const client = await pool.connect()
  try {
    for (const sql of migrations) {
      await client.query(sql)
    }
    console.log('Migration v2 complete: species_profile_id added to grows.')
  } finally {
    client.release()
    await pool.end()
  }
}

migrate().catch((err) => {
  console.error('Migration v2 failed:', err)
  process.exit(1)
})

import { Pool } from 'pg'

const pool = new Pool({
  connectionString: process.env.DATABASE_URL || 'postgresql://architect:architect_dev_2026@localhost:5432/shrooly',
})

const species = [
  {
    name: 'Psilocybe cubensis (Treasure Coast)',
    common_name: 'Treasure Coast',
    difficulty: 'beginner',
    description: 'A classic Psilocybe cubensis variety originally collected from the southern Florida coast. Known for reliable colonization, good yields, and forgiving growing conditions. Produces medium to large fruits with golden-brown caps.',
    substrate_recommendations: 'Sterile corn spawn bags (2000cc) for colonization, then pasteurized coco coir for bulk substrate. Ratio: 1 part spawn to 5 parts substrate. Vermiculite can be added for water retention.',
    troubleshooting: 'Slow colonization: ensure temperature is 25-28°C and bag is in the dark. Contamination (green/black patches): discard the bag, improve sterile technique. No pinning after full colonization: introduce fresh air exchange and light cycle. Aborts (pins that stop growing): usually caused by dry conditions or temperature swings.',
    conditions: {
      spawn_run: { temp_min: 25, temp_max: 28, humidity: 95, days_min: 14, days_max: 21, air_exchange_min: 60, light_hours: 0 },
      pinning: { temp_min: 22, temp_max: 25, humidity: 98, days_min: 5, days_max: 10, air_exchange_min: 15, light_hours: 12 },
      fruiting: { temp_min: 22, temp_max: 25, humidity: 92, days_min: 5, days_max: 7, air_exchange_min: 15, light_hours: 12 },
    },
  },
  {
    name: 'Psilocybe cubensis (McKennaii)',
    common_name: 'McKennaii',
    difficulty: 'intermediate',
    description: 'A Psilocybe cubensis variety named after ethnobotanist Terence McKenna. Considered slightly more demanding than typical cubensis strains — prefers stable conditions and higher humidity. Produces dense, medium-sized fruits with distinctive dark caps.',
    substrate_recommendations: 'Sterile corn spawn bags (2000cc) for colonization, then pasteurized coco coir for bulk substrate. Benefits from a thin casing layer of vermiculite/peat on top to maintain surface moisture. Ratio: 1 part spawn to 4-5 parts substrate.',
    troubleshooting: 'Stalling colonization: McKennaii can be slower than other cubensis — be patient, ensure steady 26-27°C. Overlay (thick white mat, no pins): scrape or fork the surface gently and increase FAE. Small fruits: usually insufficient nutrition or too-dry substrate. Side pins (growing from sides/bottom): line the container with a black bin liner before loading substrate.',
    conditions: {
      spawn_run: { temp_min: 25, temp_max: 28, humidity: 95, days_min: 16, days_max: 24, air_exchange_min: 60, light_hours: 0 },
      pinning: { temp_min: 22, temp_max: 24, humidity: 99, days_min: 7, days_max: 12, air_exchange_min: 12, light_hours: 12 },
      fruiting: { temp_min: 22, temp_max: 25, humidity: 93, days_min: 5, days_max: 8, air_exchange_min: 12, light_hours: 12 },
    },
  },
]

async function seed() {
  const client = await pool.connect()
  try {
    for (const s of species) {
      await client.query(
        `INSERT INTO species_profiles (name, common_name, difficulty, description, substrate_recommendations, troubleshooting, conditions)
         VALUES ($1, $2, $3, $4, $5, $6, $7)
         ON CONFLICT (name) DO NOTHING`,
        [s.name, s.common_name, s.difficulty, s.description, s.substrate_recommendations, s.troubleshooting, JSON.stringify(s.conditions)]
      )
    }
    console.log('Seed complete: Treasure Coast + McKennaii profiles inserted.')
  } finally {
    client.release()
    await pool.end()
  }
}

seed().catch((err) => {
  console.error('Seed failed:', err)
  process.exit(1)
})
